from openai import OpenAI
client = OpenAI()

response = client.chat.completions.create(
    model='gpt-4o',
    messages=[
        {
            'role': 'system',
            'content': 'Solve maths word problems. Show your reasoning step by step, then state the final answer.',
        },
        # Few-shot reasoning example
        {
            'role': 'user',
            'content': 'A shop has 50 items. It sells 20% on Monday and 25% of the rest on Tuesday. How many remain?',
        },
        {
            'role': 'assistant',
            'content': 'Step 1: Items sold Monday = 20% of 50 = 10. Remaining = 40.\n'
                       'Step 2: Items sold Tuesday = 25% of 40 = 10. Remaining = 30.\n'
                       'Answer: 30 items remain.',
        },
        # Real query
        {
            'role': 'user',
            'content': 'A tank holds 200 litres. 30% drains in the morning and then 40% of the rest drains in the afternoon. How much is left?',
        },
    ],
    max_tokens=200,
    temperature=0,
)
print(response.choices[0].message.content)
# Step 1: Morning drain = 30% of 200 = 60. Remaining = 140.
# Step 2: Afternoon drain = 40% of 140 = 56. Remaining = 84.
# Answer: 84 litres remain.
